// templates/mod.rs
//
// All HTML generated by Rust functions returning String.
// No template engine — zero overhead, zero mismatches.
//
// Security: every user-supplied string passes through escape_html() before
// insertion.  Template literals are trusted Rust strings only.
//
// Layout
// ──────
//   mod.rs    — shared helpers (base_layout, fmt_ts, …), statics, re-exports
//   board.rs  — index_page, board_page, catalog_page, archive_page, search_page
//   thread.rs — thread_page, render_post, render_poll
//   admin.rs  — admin_panel_page, admin_login_page, mod_log_page, …
//   forms.rs  — new_thread_form, reply_form

