// ─── Timestamp helpers ────────────────────────────────────────────────────────

pub(super) fn fmt_ts(ts: i64) -> String {
    match Utc.timestamp_opt(ts, 0) {
        chrono::LocalResult::Single(dt) => dt.format("%Y-%m-%d %H:%M:%S UTC").to_string(),
        _ => "unknown".to_string(),
    }
}

pub(super) fn fmt_ts_short(ts: i64) -> String {
    match Utc.timestamp_opt(ts, 0) {
        chrono::LocalResult::Single(dt) => dt.format("%m/%d/%y(%a)%H:%M:%S").to_string(),
        _ => "?".to_string(),
    }
}

// ─── Embed thumbnail helper ───────────────────────────────────────────────────

/// Scan raw post body text for a video embed URL and return its thumbnail URL.
/// Used by catalog and board-index summaries when the OP has no uploaded file.
pub(super) fn embed_thumb_from_body(body: &str) -> Option<String> {
    for token in body.split_whitespace() {
        let clean = token.trim_end_matches(['.', ',', ')', ';', '\'']);
        if let Some((embed_type, id)) = crate::utils::sanitize::extract_video_embed(clean) {
            if embed_type == "youtube" {
                return Some(format!("https://img.youtube.com/vi/{}/mqdefault.jpg", id));
            }
        }
    }
    None
}

// ─── Pagination helper ────────────────────────────────────────────────────────

pub(super) fn render_pagination(p: &Pagination, base_url: &str) -> String {
    if p.total_pages() <= 1 {
        return String::new();
    }
    let sep = if base_url.contains('?') { "&" } else { "?" };
    let mut html = String::from(r#"<div class="pagination">"#);

    if p.has_prev() {
        html.push_str(&format!(
            r#"<a href="{}{sep}page={}">[prev]</a> "#,
            base_url,
            p.page - 1,
            sep = sep
        ));
    }
    html.push_str(&format!("page {} / {}", p.page, p.total_pages()));
    if p.has_next() {
        html.push_str(&format!(
            r#" <a href="{}{sep}page={}">[next]</a>"#,
            base_url,
            p.page + 1,
            sep = sep
        ));
    }

    html.push_str("</div>");
    html
}

// FIX[LOW-9]: Encode each UTF-8 *byte*, not each Unicode codepoint.
// RFC 3986 percent-encoding operates on bytes.
pub(super) fn urlencoding_simple(s: &str) -> String {
    let mut out = String::with_capacity(s.len() * 3);
    for &byte in s.as_bytes() {
        match byte {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => {
                out.push(byte as char)
            }
            b' ' => out.push('+'),
            b => out.push_str(&format!("%{:02X}", b)),
        }
    }
    out
}

// ─── Base layout ─────────────────────────────────────────────────────────────

pub(super) fn base_layout(
    title: &str,
    board_short: Option<&str>,
    body: &str,
    csrf_token: &str,
    boards: &[Board],
    collapse_greentext: bool,
    _allow_archive: bool,
) -> String {
    let inner_links: String = boards
        .iter()
        .map(|b| {
            format!(
                r#"<a href="/{s}/catalog">{s}</a>"#,
                s = escape_html(&b.short_name)
            )
        })
        .collect::<Vec<_>>()
        .join(" / ");
    let board_links = if inner_links.is_empty() {
        String::new()
    } else {
        format!("[ {} ]", inner_links)
    };

    let search_bar = if let Some(b) = board_short {
        format!(
            r#"<form class="search-form" method="GET" action="/{b}/search">
<input type="text" name="q" placeholder="search /{b}/…" maxlength="64">
<button type="submit">go</button>
</form>"#,
            b = escape_html(b)
        )
    } else {
        String::new()
    };

    let default_theme = live_default_theme();
    // Only inject the attribute when a non-default theme is configured — no
    // attribute means "terminal" (the built-in default), matching the
    // client-side behaviour in theme-init.js.
    let default_theme_attr = if !default_theme.is_empty() && default_theme != "terminal" {
        format!(r#" data-default-theme="{}""#, escape_html(&default_theme))
    } else {
        String::new()
    };

    format!(
        r#"<!DOCTYPE html>
<html lang="en"{default_theme_attr}>
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<meta name="referrer" content="no-referrer">
<title>{title}</title>
<link rel="stylesheet" href="/static/style.css">
<script src="/static/theme-init.js"></script>
</head>
<body{collapse_attr}>
<header class="site-header">
  <span class="site-name">{forum_name}</span>
  <a class="home-btn" href="/">&#8962; Home</a>
  <nav class="board-list">
    {board_links}
  </nav>
  <div class="header-search">{search_bar}</div>
  <a class="admin-header-link" href="/admin">[Admin]</a>
</header>
<main>
{body}
</main>
<footer class="site-footer">
  <p>{forum_name} &mdash; <a href="/">home</a></p>
</footer>

<!-- Theme Picker — FIX[NEW-H1]: onclick= replaced with data-action= attributes -->
<button id="theme-picker-btn" data-action="toggle-theme-picker" title="Select Theme">&#127912; Theme</button>
<div id="theme-picker-panel">
  <div class="tp-title">// SELECT THEME</div>
  <button class="tp-option" data-action="set-theme" data-theme="terminal">
    <span class="tp-swatch" style="background:#00ff41;"></span>Terminal
  </button>
  <button class="tp-option" data-action="set-theme" data-theme="aero">
    <span class="tp-swatch" style="background:#6aaed6;"></span>Frutiger Aero
  </button>
  <button class="tp-option" data-action="set-theme" data-theme="dorfic">
    <span class="tp-swatch" style="background:#ffcc66;"></span>DORFic
  </button>
  <button class="tp-option" data-action="set-theme" data-theme="fluorogrid">
    <span class="tp-swatch" style="background:#8833aa;"></span>FluoroGrid
  </button>
  <button class="tp-option" data-action="set-theme" data-theme="neoncubicle">
    <span class="tp-swatch" style="background:#b03888;"></span>NeonCubicle
  </button>
</div>

<input type="hidden" id="csrf_global" value="{csrf_token}">
<script src="/static/main.js" defer></script>
</body>
</html>"#,
        title = escape_html(title),
        board_links = board_links,
        search_bar = search_bar,
        forum_name = escape_html(&live_site_name()),
        body = body,
        csrf_token = escape_html(csrf_token),
        default_theme_attr = default_theme_attr,
        collapse_attr = if collapse_greentext {
            " data-collapse-greentext=\"1\""
        } else {
            ""
        },
    )
}

// ─── Standalone error/ban pages (no board context) ────────────────────────────

pub fn ban_page(reason: &str) -> String {
    let default_theme = live_default_theme();
    let default_theme_attr = if !default_theme.is_empty() && default_theme != "terminal" {
        format!(r#" data-default-theme="{}""#, escape_html(&default_theme))
    } else {
        String::new()
    };
    format!(
        r#"<!DOCTYPE html>
<html lang="en"{default_theme_attr}>
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>You Are Banned</title>
<link rel="stylesheet" href="/static/style.css">
<script src="/static/theme-init.js"></script>
</head>
<body>
<div class="page-box error-page">
<h1>you are banned</h1>
<p style="color:var(--text-dim)">reason: <strong>{reason}</strong></p>
<p style="margin-top:1.5rem;font-size:0.9rem">if you believe this ban was made in error, you may submit an appeal below.<br>
appeals are reviewed by site staff. one appeal per 24 hours.</p>
<form method="POST" action="/appeal" class="appeal-form">
<input type="hidden" name="_csrf" id="appeal-csrf-field" value="">
<textarea name="reason" rows="4" maxlength="512"
  placeholder="Briefly explain why you believe this ban should be lifted…"
  style="width:100%;box-sizing:border-box;margin:0.75rem 0;background:var(--bg-post);color:var(--text);border:1px solid var(--border);padding:0.5rem;resize:vertical"></textarea>
<button type="submit" style="margin-top:0.25rem">submit appeal</button>
</form>
<p style="margin-top:1.5rem"><a href="/">return home</a></p>
</div>
</body>
</html>"#,
        default_theme_attr = default_theme_attr,
        reason = escape_html(reason),
    )
}

pub fn error_page(code: u16, message: &str) -> String {
    let default_theme = live_default_theme();
    let default_theme_attr = if !default_theme.is_empty() && default_theme != "terminal" {
        format!(r#" data-default-theme="{}""#, escape_html(&default_theme))
    } else {
        String::new()
    };
    format!(
        r#"<!DOCTYPE html>
<html lang="en"{default_theme_attr}>
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Error {code}</title>
<link rel="stylesheet" href="/static/style.css">
<script src="/static/theme-init.js"></script>
</head>
<body>
<div class="page-box error-page">
<h1>error {code}</h1>
<p>{message}</p>
<p><a href="/">return home</a></p>
</div>
</body>
</html>"#,
        default_theme_attr = default_theme_attr,
        code = code,
        message = escape_html(message),
    )
}
